/** Full-page MH voucher form routes (internal scroll via `pageVoucher`). */
const MH_VOUCHER_FORM_MODULES = new Set(['ycmh', 'ddmh', 'nhan-hang']);

export function isVoucherFormPath(pathname: string): boolean {
  const parts = pathname.split('/').filter(Boolean);
  if (parts.length < 3) return false;
  const [domain, module, action] = parts;
  if (domain !== 'mh') return false;
  if (!MH_VOUCHER_FORM_MODULES.has(module)) return false;
  return action === 'them' || action.length > 0;
}
